import hashlib
import time
from functools import wraps
from typing import Callable, Any

def cache_result_expiration(ttl: int = 60, max_size: int = 100):
    cache = {}
    cache_size = 0

    def decorator(func: Callable) -> Callable:
        @wraps(func)
        def wrapper(*args: Any, **kwargs: Any) -> Any:
            key = str(args) + str(kwargs)
            if key in cache:
                if time.time() - cache[key]['timestamp'] < ttl:
                    return cache[key]['result']
                else:
                    del cache[key]
            if cache_size >= max_size:
                del cache[max(cache.keys())]
            cache[key] = {'result': func(*args, **kwargs), 'timestamp': time.time()}
            return cache[key]['result']

        return wrapper

    return decorator

def anonymize_email(email: str) -> str:
    salt = hashlib.sha256(str(time.time()).encode()).digest()[:32]
    hashed_email = hashlib.pbkdf2_hmac('sha256', email.encode(), salt, 100000)
    return hashed_email.hex()

# Example usage:
@cache_result_expiration(ttl=300, max_size=50)
def example_function(email: str) -> str:
    print(anonymize_email(email))
    return f"Hello, {email}!"

print(example_function("user@example.com"))
