import argparse
import os
import re

class FileProcessStrategy:
    def rename_files(self, directory, pattern, replacement):
        for filename in os.listdir(directory):
            if re.match(pattern, filename):
                os.rename(os.path.join(directory, filename), 
                          os.path.join(directory, re.sub(pattern, replacement, filename)))

class RegexFileProcessStrategy(FileProcessStrategy):
    def rename_files(self, directory, pattern, replacement):
        super().rename_files(directory, pattern, replacement)

class GlobFileProcessStrategy(FileProcessStrategy):
    def rename_files(self, directory, pattern, replacement):
        super().rename_files(directory, pattern, replacement)

class StringFileProcessStrategy(FileProcessStrategy):
    def rename_files(self, directory, pattern, replacement):
        super().rename_files(directory, pattern, replacement)

def main():
    parser = argparse.ArgumentParser(description='Rename files in bulk using regex patterns')
    parser.add_argument('-d', '--directory', required=True, help='directory to process')
    parser.add_argument('-p', '--pattern', required=True, help='regex pattern to match')
    parser.add_argument('-r', '--replacement', required=True, help='replacement string')
    args = parser.parse_args()

    strategies = {
        'regex': RegexFileProcessStrategy(),
        'glob': GlobFileProcessStrategy(),
        'string': StringFileProcessStrategy(),
    }

    strategy = strategies.get(args.strategy, RegexFileProcessStrategy())
    strategy.rename_files(args.directory, args.pattern, args.replacement)

if __name__ == "__main__":
    main()
