from abc import ABC, abstractmethod

# Strategy interface
class CacheStrategy(ABC):
    @abstractmethod
    def get(self, key):
        pass

    @abstractmethod
    def set(self, key, value):
        pass

# InMemoryCache strategy
class InMemoryCache(CacheStrategy):
    def __init__(self):
        self.cache = {}

    def get(self, key):
        return self.cache.get(key)

    def set(self, key, value):
        self.cache[key] = value

# Fibonacci function with memoization and decoupled caching
class Fibonacci:
    def __init__(self, cache_strategy):
        self.cache_strategy = cache_strategy
        self.cache = {}

    def fib(self, n):
        if n < 2:
            return n
        if n not in self.cache:
            self.cache[n] = self.fib(n-1) + self.fib(n-2)
        return self.cache_strategy.get(n, self.cache[n])

# Example usage
if __name__ == "__main__":
    cache_strategy = InMemoryCache()
    fib = Fibonacci(cache_strategy)

    print(fib.fib(10))  # Output: 55
    print(fib.fib(10))  # Output: 55 (cached result)
