import enum

class TcpConnectionStates(enum.Enum):
    LISTENING = 1
    ESTABLISHED = 2
    CLOSED = 3

class TcpStateMachine:
    def __init__(self):
        self.state = TcpConnectionStates.LISTENING
        self.connected = False

    def connect(self):
        if self.state == TcpConnectionStates.LISTENING:
            self.state = TcpConnectionStates.ESTABLISHED
            self.connected = True
        elif self.state == TcpConnectionStates.ESTABLISHED:
            self.state = TcpConnectionStates.ESTABLISHED
        elif self.state == TcpConnectionStates.CLOSED:
            raise ValueError("Connection is already closed")

    def close(self):
        if self.state == TcpConnectionStates.ESTABLISHED:
            self.state = TcpConnectionStates.CLOSED
            self.connected = False
        elif self.state == TcpConnectionStates.LISTENING or self.state == TcpConnectionStates.CLOSED:
            raise ValueError("Connection is not established")

    def is_connected(self):
        return self.connected

    def get_state(self):
        return self.state
