    INSERT INTO Updates (stock_id, price)
    VALUES (@stock_id, @price);
END;

CREATE PROCEDURE notify_observers(
    @stock_id INT
)
AS
BEGIN
    INSERT INTO Updates (stock_id, price)
    VALUES (@stock_id, (SELECT price FROM Stocks WHERE id = @stock_id));

    SELECT * FROM Observers WHERE stock_id = @stock_id;
