import numpy as np

class Optimizer:
    def __init__(self, learning_rate):
        self.learning_rate = learning_rate

    def update(self, params, gradient):
        return params - self.learning_rate * gradient


class GradientDescentOptimizer(Optimizer):
    def __init__(self, learning_rate, learning_rate_decay=0.99, decay_step=1):
        super().__init__(learning_rate)
        self.learning_rate_decay = learning_rate_decay
        self.decay_step = decay_step
        self.iteration = 0

    def update(self, params, gradient):
        update = super().update(params, gradient)
        if self.iteration % self.decay_step == 0:
            self.learning_rate *= self.learning_rate_decay
        return update


class SGD(Optimizer):
    def __init__(self, learning_rate):
        super().__init__(learning_rate)


class MomentumOptimizer(Optimizer):
    def __init__(self, learning_rate, momentum=0.9):
        super().__init__(learning_rate)
        self.momentum = momentum
        self.velocity = np.zeros_like(super().params)

    def update(self, params, gradient):
        self.velocity = self.momentum * self.velocity + self.learning_rate * gradient
        return params - self.velocity


class RMSPropOptimizer(Optimizer):
    def __init__(self, learning_rate, decay_rate=0.99, epsilon=1e-8):
        super().__init__(learning_rate)
        self.decay_rate = decay_rate
        self.epsilon = epsilon
        self.cache = np.zeros_like(super().params)

    def update(self, params, gradient):
        self.cache = self.decay_rate * self.cache + (1 - self.decay_rate) * gradient ** 2
        return params - self.learning_rate * gradient / np.sqrt(self.cache + self.epsilon)


class AdamOptimizer(Optimizer):
    def __init__(self, learning_rate, beta1=0.9, beta2=0.999, epsilon=1e-8):
        super().__init__(learning_rate)
        self.beta1 = beta1
        self.beta2 = beta2
        self.epsilon = epsilon
        self.m = np.zeros_like(super().params)
        self.v = np.zeros_like(super().params)

    def update(self, params, gradient):
        self.m = self.beta1 * self.m + (1 - self.beta1) * gradient
        self.v = self.beta2 * self.v + (1 - self.beta2) * gradient ** 2
        return params - self.learning_rate * self.m / np.sqrt(self.v + self.epsilon)


class NesterovOptimizer(Optimizer):
    def __init__(self, learning_rate, momentum=0.9):
        super().__init__(learning_rate)
        self.momentum = momentum
        self.velocity = np.zeros_like(super().params)

    def update(self, params, gradient):
        self.velocity = self.momentum * self.velocity + self.learning_rate * gradient
        return params - self.velocity


class Strategy:
    def __init__(self, optimizer):
        self.optimizer = optimizer

    def update(self, params, gradient):
        return self.optimizer.update(params, gradient)


class GradientDescentStrategy(Strategy):
    def __init__(self, optimizer, learning_rate):
        super().__init__(optimizer)
        self.learning_rate = learning_rate

    def update(self, params, gradient):
        update = self.optimizer.update(params, gradient)
        return update


class SGDStrategy(Strategy):
    def __init__(self, optimizer, learning_rate):
        super().__init__(optimizer)
        self.learning_rate = learning_rate

    def update(self, params, gradient):
        update = self.optimizer.update(params, gradient)
        return update


class MomentumStrategy(Strategy):
    def __init__(self, optimizer, learning_rate, momentum):
        super().__init__(optimizer)
        self.learning_rate = learning_rate
        self.momentum = momentum

    def update(self, params, gradient):
        update = self.optimizer.update(params, gradient)
        return update


class RMSPropStrategy(Strategy):
    def __init__(self, optimizer, learning_rate, decay_rate, epsilon):
        super().__init__(optimizer)
        self.learning_rate = learning_rate
        self.decay_rate = decay_rate
        self.epsilon = epsilon

    def update(self, params, gradient):
        update = self.optimizer.update(params, gradient)
        return update


class AdamStrategy(Strategy):
    def __init__(self, optimizer, learning_rate, beta1, beta2, epsilon):
        super().__init__(optimizer)
        self.learning_rate = learning_rate
        self.beta1 = beta1
        self.beta2 = beta2
        self.epsilon = epsilon

    def update(self, params, gradient):
        update = self.optimizer.update(params, gradient)
        return update


class NesterovStrategy(Strategy):
    def __init__(self, optimizer, learning_rate, momentum):
        super().__init__(optimizer)
        self.learning_rate = learning_rate
        self.momentum = momentum

    def update(self, params, gradient):
        update = self.optimizer.update(params, gradient)
        return update


if __name__ == "__main__":
    params = np.array([1.0, 2.0, 3.0])
    gradient = np.array([1.0, 2.0, 3.0])

    # Gradient Descent
    optimizer = GradientDescentOptimizer(learning_rate=0.01)
    strategy = GradientDescentStrategy(optimizer, learning_rate=0.01)
    updated_params = strategy.update(params, gradient)
    print(updated_params)

    # SGD
