    strategy = SGDStrategy(optimizer, learning_rate=0.01)
    updated_params = strategy.update(params, gradient)
    print(updated_params)

    # Momentum
    optimizer = MomentumOptimizer(learning_rate=0.01, momentum=0.9)
    strategy = MomentumStrategy(optimizer, learning_rate=0.01, momentum=0.9)
    updated_params = strategy.update(params, gradient)
    print(updated_params)

    # RMSProp
    optimizer = RMSPropOptimizer(learning_rate=0.01, decay_rate=0.99, epsilon=1e-8)
    strategy = RMSPropStrategy(optimizer, learning_rate=0.01, decay_rate=0.99, epsilon=1e-8)
    updated_params = strategy.update(params, gradient)
    print(updated_params)

    # Adam
