import redis
import secrets
import time

class SecureSessionStore:
    def __init__(self, redis_host='localhost', redis_port=6379, session_expiration=3600):
        self.redis_client = redis.Redis(host=redis_host, port=redis_port)
        self.session_expiration = session_expiration

    def create_session(self, user_id, session_token):
        session_key = f'session:{user_id}'
        session_data = {'user_id': user_id, 'session_token': session_token}
        self.redis_client.hmset(session_key, session_data)
        self.redis_client.expire(session_key, self.session_expiration)
        return session_key

    def get_session(self, session_key):
        session_data = self.redis_client.hgetall(session_key)
        if session_data:
            return session_data
        return None

    def update_session(self, session_key, user_id, session_token):
        session_data = self.get_session(session_key)
        if session_data:
            session_data['user_id'] = user_id
            session_data['session_token'] = session_token
            self.redis_client.hmset(session_key, session_data)
        return session_key

    def delete_session(self, session_key):
        self.redis_client.delete(session_key)

    def verify_session_token(self, session_key, session_token):
        session_data = self.get_session(session_key)
        if session_data and session_data['session_token'] == session_token:
            return True
        return False

def generate_session_token(length=32):
    return secrets.token_urlsafe(length)

def main():
    session_store = SecureSessionStore()
    user_id = '12345'
    session_token = generate_session_token()
    session_key = session_store.create_session(user_id, session_token)
    print(f'Session Key: {session_key}')
    print(f'Session Token: {session_token}')
    print(f'Is Session Valid: {session_store.verify_session_token(session_key, session_token)}')
    session_store.update_session(session_key, user_id, session_token)
    print(f'Is Session Valid after update: {session_store.verify_session_token(session_key, session_token)}')
    time.sleep(1)
    print(f'Is Session Valid after expiration: {session_store.verify_session_token(session_key, session_token)}')

if __name__ == '__main__':
    main()
