class HTMLTransformer(Plugin):
    def transformer(self, markdown):
        # Simple HTML transformer
        return f"<html><body>{markdown}</body></html>"


class Registry:
    def __init__(self):
        self.transformers = []

    def register_transformer(self, transformer):
        self.transformers.append(transformer)

    def get_transformer(self, name):
        for transformer in self.transformers:
            if transformer.name == name:
                return transformer.transformer
        return None


def main():
    registry = Registry()

    markdown_transformer = MarkdownTransformer("markdown")
    html_transformer = HTMLTransformer("html")

    markdown_transformer.register(registry)
    html_transformer.register(registry)

    markdown = "hello world"
    html = registry.get_transformer("html").markdown

    print(f"Markdown: {markdown}")
    print(f"HTML: {html}")


if __name__ == "__main__":
    main()
