CREATE TABLE products (
  id INT PRIMARY KEY,
  name VARCHAR(255),
  price DECIMAL(10, 2)
);

CREATE TABLE orders (
  id INT PRIMARY KEY,
  product_id INT,
  quantity INT,
  FOREIGN KEY (product_id) REFERENCES products(id)
);

-- Service Layer
CREATE PROCEDURE get_product_by_id(
  @product_id INT
)
RETURNS TABLE
AS
RETURN (
  SELECT p.id, p.name, p.price
  FROM products p
  WHERE p.id = @product_id
);

CREATE PROCEDURE create_order(
  @product_id INT,
  @quantity INT
)
AS
BEGIN
  INSERT INTO orders (product_id, quantity)
  VALUES (@product_id, @quantity);
END;

-- Business Logic
CREATE TABLE order_items (
  id INT PRIMARY KEY,
  order_id INT,
  product_id INT,
  quantity INT,
  FOREIGN KEY (order_id) REFERENCES orders(id),
  FOREIGN KEY (product_id) REFERENCES products(id)
);

CREATE PROCEDURE update_order_quantity(
  @order_id INT,
  @product_id INT,
  @new_quantity INT
)
AS
BEGIN
  IF NOT EXISTS (SELECT 1 FROM orders WHERE id = @order_id)
    RAISERROR ('Order not found', 16, 1);

  IF NOT EXISTS (SELECT 1 FROM order_items WHERE order_id = @order_id AND product_id = @product_id)
    INSERT INTO order_items (order_id, product_id, quantity)
    VALUES (@order_id, @product_id, @new_quantity);

  ELSE
    UPDATE order_items
    SET quantity = @new_quantity
    WHERE order_id = @order_id AND product_id = @product_id;
END;
