import mmap
import os
import re

class LogParser:
    def __init__(self, filename):
        self.filename = filename
        self.file_size = os.path.getsize(filename)
        self.mmap_file = self._mmap_file()

    def _mmap_file(self):
        if self.file_size <= 1024 * 1024 * 10:
            return open(self.filename, 'r')
        else:
            return mmap.mmap(-1, self.file_size, access=mmap.ACCESS_READ)

    def parse(self):
        for line in self.mmap_file:
            yield from self._parse_line(line.decode())

    def _parse_line(self, line):
        for match in re.finditer(r'(\w+)\s+(\w+)\s+(\w+)', line):
            yield {
                'timestamp': match.group(1),
                'level': match.group(2),
                'message': match.group(3)
            }

if __name__ == '__main__':
    parser = LogParser('log_file.log')
    for log in parser.parse():
        print(log)
