const (
    port     = 8080
    logLevel = level.Debug
)

var (
    config = viper.New()
    logger *zap.Logger
)

func main() {
    // Load configuration
    err := config.ReadInConfig()
    if err != nil {
        log.Fatal(err)
    }

    // Initialize logger
    logger, err = loggers.GetLogger(logLevel)
    if err != nil {
        log.Fatal(err)
    }

    // Create HTTP server
    srv := http.Server{
        Addr:         ":8080",
        ReadTimeout:  10 * time.Second,
        WriteTimeout: 10 * time.Second,
        MaxHeaderBytes: 1 << 20,
    }

    // Register handlers
    srv.HandleFunc("/health", healthCheck)
    srv.HandleFunc("/metrics", metricsHandler)

    // Start server
    logger.Info("Starting server on port 8080")
    log.Fatal(srv.ListenAndServe())
}

func healthCheck(w http.ResponseWriter, r *http.Request) {
    logger.Info("Received health check request")
    w.Write([]byte("ok"))
}

func metricsHandler(w http.ResponseWriter, r *http.Request) {
    logger.Info("Received metrics request")
    w.Write([]byte("ok"))
}

func registerFallbacks(srv *http.Server) {
    // Register fallbacks for external dependencies
    fallbacks := map[string]func(string) string{
        "external-api": externalAPIFallback,
    }

    // Register fallback handlers
    for name, fallback := range fallbacks {
        srv.HandleFunc(name, fallback)
    }
}

func externalAPIFallback(path string) string {
    logger.Warn("External API failed")
    return "fallback"
}

func registerStructuredLogging(srv *http.Server) {
    // Register structured logging
    log.Logger = zap.New(
        zap.NewFileLogger(os.Stdout, "log.log", zap.AddCaller),
        zap.AddEncoderConfig(zap.NewJSONEncoder()),
    )

    // Set log level
    log.Logger.SetLevel(logLevel)

    // Register handlers
    srv.Logger = log.Logger
}

func registerInvalidRequestHandling(srv *http.Server) {
    // Register handlers for invalid requests
    srv.HandleFunc("/invalid-request", func(w http.ResponseWriter, r *http.Request) {
        logger.Error("Received invalid request")
        w.WriteHeader(http.StatusBadRequest)
    })
}

func registerCorruptedDataHandling(srv *http.Server) {
    // Register handlers for corrupted data
    srv.HandleFunc("/corrupted-data", func(w http.ResponseWriter, r *http.Request) {
        logger.Error("Received corrupted data")
        w.WriteHeader(http.StatusBadRequest)
    })
}

func main() {
    // Register fallbacks
    registerFallbacks(&http.Server{})

    // Register structured logging
    registerStructuredLogging(&http.Server{})

    // Register invalid request handling
    registerInvalidRequestHandling(&http.Server{})

    // Register corrupted data handling
    registerCorruptedDataHandling(&http.Server{})

    // Start server
    http.ListenAndServe(":8080", nil)
}
