package main

import (
    "context"
    "fmt"
    "log"
    "sync"
    "time"

    "github.com/Shopify/sarama"
)

const (
    // Define the topic name
    topicName = "signup-events"

    // Define the broker configuration
    brokerConfig = "localhost:9092"

    // Define the consumer group name
    consumerGroup = "signup-consumer"

    // Define the worker count
    workerCount = 5
)

// Message represents a message to be processed
type Message struct {
    ID  string
    Data string
}

// MessageQueueConsumer is a consumer that processes incoming messages
type MessageQueueConsumer struct {
    sync.RWMutex
    producer *sarama.Producer
    consumer *sarama.ConsumerGroup
    topics    []string
}

// NewMessageQueueConsumer returns a new MessageQueueConsumer instance
func NewMessageQueueConsumer(brokerConfig, topicName, consumerGroup string, workerCount int) (*MessageQueueConsumer, error) {
    // Create a new Sarama producer
    producer, err := sarama.NewProducer(sarama.NewURLs(brokerConfig))
    if err != nil {
        return nil, err
    }

    // Create a new Sarama consumer group
    consumer, err := sarama.NewConsumerGroup(context.Background(), consumerGroup, sarama.NewURLs(brokerConfig))
    if err != nil {
        return nil, err
    }

    // Subscribe to the topic
    err = consumer.Subscribe(context.Background(), topicName, nil)
    if err != nil {
        return nil, err
    }

    // Create a new MessageQueueConsumer instance
    consumer := &MessageQueueConsumer{
        producer: producer,
        consumer: consumer,
        topics:   []string{topicName},
    }

    return consumer, nil
}

// Start starts the consumer and processes incoming messages
func (c *MessageQueueConsumer) Start() {
    // Start the consumer
    err := c.consumer.Start()
    if err != nil {
        log.Fatal(err)
    }

    // Process incoming messages
    for {
        select {
        case msg, ok := <-c.consumer.Messages():
            if !ok {
                break
            }
            c.processMessage(msg)
        case <-time.After(time.Second * 1):
            // Periodically restart the consumer
            err := c.consumer.Restart(context.Background())
            if err != nil {
                log.Println(err)
            }
        }
    }
}

// processMessage processes a single message
func (c *MessageQueueConsumer) processMessage(msg *sarama.Message) {
    // Lock the mutex to ensure exclusive access
    c.Lock()
    defer c.Unlock()

    // Process the message
    data := string(msg.Value)
    fmt.Printf("Received message: %s\n", data)

    // Acknowledge the message
    err := c.producer_ACK(context.Background(), msg)
    if err != nil {
        log.Println(err)
    }
}

func main() {
    // Create a new MessageQueueConsumer instance
    consumer, err := NewMessageQueueConsumer(brokerConfig, topicName, consumerGroup, workerCount)
    if err != nil {
        log.Fatal(err)
    }

    // Start the consumer
    go consumer.Start()
}
