    let matches = App::new("Task Manager")
        .version("1.0")
        .author("Your Name")
        .about("A CLI task management tool")
        .arg(
            Arg::with_name("help")
                .long("help")
                .help("Show this message"),
        )
        .arg(
            Arg::with_name("version")
                .long("version")
                .help("Show version"),
        )
        .arg(
            Arg::with_name("add")
                .long("add")
                .help("Add a new task"),
        )
        .arg(
            Arg::with_name("complete")
                .long("complete")
                .help("Mark a task as completed"),
        )
        .arg(
            Arg::with_name("status")
                .long("status")
                .help("Show the status of a task"),
        )
        .arg(
            Arg::with_name("id")
                .long("id")
                .help("Task ID")
                .takes_value(true),
        )
        .get_matches();

