        if matches.is_present("version") {
            println!("Task Manager v1.0");
        }
        println!("Task Manager usage:");
        println!("  task --help     Show this message");
        println!("  task --version  Show version");
        return;
    }

    if matches.is_present("add") {
        let id = matches.value_of("id").unwrap().to_string();
        let title = matches.value_of("title").unwrap().to_string();
        let description = matches.value_of("description").unwrap().to_string();
        let task = Task::new(id, title, description);
        println!("Task added successfully!");
    } else if matches.is_present("complete") {
        let id = matches.value_of("id").unwrap().to_string();
        if let Some(task) = Task::get(id) {
            task.completed = true;
            println!("Task completed successfully!");
        } else {
            println!("Task not found!");
        }
    } else if matches.is_present("status") {
        let id = matches.value_of("id").unwrap().to_string();
        if let Some(task) = Task::get(id) {
            match task.completed {
                true => println!("Task completed"),
                false => println!("Task not completed"),
            }
        } else {
            println!("Task not found!");
        }
    } else {
        println!("Invalid command!");
    }
}

fn get(id: &str) -> Option<Task> {
