import pytest
import logging
import os

# Define logging configuration
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Define type hints
T = TypeVar('T')

# Abstract base class for extractors
class Extractor(ABC, Generic[T]):
    @abstractmethod
    def extract(self, data: T) -> T:
        pass

# Abstract base class for transformers
class Transformer(ABC, Generic[T]):
    @abstractmethod
    def transform(self, data: T) -> T:
        pass

# Abstract base class for loaders
class Loader(ABC, Generic[T]):
    @abstractmethod
    def load(self, data: T) -> T:
        pass

# Data class for pipeline configuration
@dataclass
class PipelineConfig:
    extractor: Extractor[T]
    transformer: Transformer[T]
    loader: Loader[T]

# Pipeline class
class Pipeline:
    def __init__(self, config: PipelineConfig):
        self.config = config

    def run(self, data: T) -> T:
        data = self.config.extractor.extract(data)
        data = self.config.transformer.transform(data)
        return self.config.loader.load(data)

# Fixtures for testing
@pytest.fixture
def extractor_fixture():
