import time
import random
import threading

class CircuitBreaker:
    def __init__(self, threshold=5, timeout=30):
        self.threshold = threshold
        self.timeout = timeout
        self.failure_count = 0
        self.recovery_count = 0
        self.breaker_open = False
        self.last_failure_time = 0
        self.lock = threading.Lock()

    def is_open(self):
        return self.breaker_open

    def is_half_open(self):
        with self.lock:
            if self.failure_count > 0 and self.failure_count < self.threshold:
                return True
            return False

    def is_closed(self):
        with self.lock:
            return not self.breaker_open and self.failure_count == 0

    def circuit_breaker(self, func):
        def wrapper(*args, **kwargs):
            if self.breaker_open:
                return "Circuit is open"
            if self.is_half_open():
                return "Half-open, attempting to recover"

            start_time = time.time()
            try:
                result = func(*args, **kwargs)
                if time.time() - start_time > self.timeout:
                    raise Exception("Timeout exceeded")
                self.failure_count = 0
                self.recovery_count = 0
                return result
            except Exception as e:
                self.failure_count += 1
                if self.failure_count >= self.threshold:
                    self.breaker_open = True
                    self.last_failure_time = time.time()
                    return "Circuit is open"
                else:
                    if time.time() - self.last_failure_time > 30:
                        self.breaker_open = False
                        self.failure_count = 0
                        self.recovery_count += 1
                        return func(*args, **kwargs)

        return wrapper

def example_function():
    # Simulate an HTTP request
    time.sleep(random.uniform(0.1, 1))
    if random.random() < 0.5:
        raise Exception("Failed request")
    return "Request succeeded"

breaker = CircuitBreaker()
@breaker.circuit_breaker
def request_service():
    return example_function()

print(request_service())
