import hashlib
import logging
import random
import string
import time
from collections import defaultdict

class VirtualNode:
    def __init__(self, id, hash_value):
        self.id = id
        self.hash_value = hash_value

class Node:
    def __init__(self, id, host, port):
        self.id = id
        self.host = host
        self.port = port
        self.virtual_nodes = {}

    def add_virtual_node(self, virtual_node):
        self.virtual_nodes[virtual_node.id] = virtual_node

    def remove_virtual_node(self, virtual_node_id):
        if virtual_node_id in self.virtual_nodes:
            del self.virtual_nodes[virtual_node_id]

class ConsistentHash:
    def __init__(self, ring):
        self.ring = ring

    def _hash(self, key):
        return int(hashlib.md5(key.encode()).hexdigest(), 16)

    def _hash_function(self, key):
        return self._hash(key) % len(self.ring)

    def _get_ring(self, key):
        ring = self.ring
        hash_value = self._hash(key)
        for i, node in enumerate(ring):
            if hash_value < i:
                return node
            elif hash_value > i + len(ring) - 1:
                return ring[i]
            else:
                return ring[i]

    def add_node(self, node):
        self.ring.append(node)
        ring = self.ring
        for i, node in enumerate(ring):
            if node not in self.ring:
                self.ring.insert(i, node)

    def remove_node(self, node):
        self.ring.remove(node)

    def get_virtual_node(self, key):
        return self._get_ring(key)

class GossipProtocol:
    def __init__(self, nodes):
        self.nodes = nodes
        self.membership = set(nodes)

    def join(self, node):
        self.membership.add(node)
        for other_node in self.nodes:
            if other_node != node:
                self.send_join_notification(other_node)

    def leave(self, node):
        self.membership.remove(node)
        for other_node in self.nodes:
            if other_node != node:
                self.send_leave_notification(other_node)

    def send_join_notification(self, node):
        logging.info(f"Sending join notification to {node.host}:{node.port}")

    def send_leave_notification(self, node):
        logging.info(f"Sending leave notification to {node.host}:{node.port}")

class ShardedKeyValueStore:
    def __init__(self, num_shards):
        self.num_shards = num_shards
        self.shard_map = {}
        self.gossip_protocol = GossipProtocol([Node(1, "host1", 8080), Node(2, "host2", 8081)])

    def put(self, key, value):
        hash_value = self._hash(key)
        shard_id = hash_value % self.num_shards
        shard_ring = [self.shard_map.get(f"shard-{i}", None) for i in range(self.num_shards)]
        shard_ring[shard_id] = self.shard_map.get(f"shard-{shard_id}", None)
        virtual_node = self.gossip_protocol.get_virtual_node(key)
        shard_node = self._get_shard_node(shard_ring, virtual_node.id)
        shard_node.add_virtual_node(virtual_node)
        logging.info(f"Storing key={key}, value={value} in shard={shard_id}")
        shard_node.put(key, value)

    def get(self, key):
        hash_value = self._hash(key)
        shard_id = hash_value % self.num_shards
        shard_ring = [self.shard_map.get(f"shard-{i}", None) for i in range(self.num_shards)]
        shard_ring[shard_id] = self.shard_map.get(f"shard-{shard_id}", None)
        virtual_node = self.gossip_protocol.get_virtual_node(key)
        shard_node = self._get_shard_node(shard_ring, virtual_node.id)
        return shard_node.get(key)

    def _hash(self, key):
        return int(hashlib.md5(key.encode()).hexdigest(), 16)

    def _hash_function(self, key):
        return self._hash(key) % self.num_shards

    def _get_shard_node(self, shard_ring, virtual_node_id):
        for node in shard_ring:
            if node and virtual_node_id in node.virtual_nodes:
                return node
        raise Exception(f"No shard node found for virtual node {virtual_node_id}")

    def _add_node_to_shard_ring(self, node):
        shard_id = node.id % self.num_shards
        shard_ring = [self.shard_map.get(f"shard-{i}", None) for i in range(self.num_shards)]
        shard_ring[shard_id] = self.shard_map.get(f"shard-{shard_id}", None)
        shard_ring[shard_id].add_virtual_node(node.virtual_nodes.pop(node.id))
        self.shard_map[f"shard-{shard_id}"] = shard_ring[shard_id]

    def _remove_node_from_shard_ring(self, node):
        shard_id = node.id % self.num_shards
        shard_ring = [self.shard_map.get(f"shard-{i}", None) for i in range(self.num_shards)]
        shard_ring[shard_id].remove(node.virtual_nodes.pop(node.id))
        if len(shard_ring[shard_id].virtual_nodes) == 0:
            del self.shard_map[f"shard-{shard_id}"]

    def join_node(self, node):
        self.gossip_protocol.join(node)
        self._add_node_to_shard_ring(node)

    def leave_node(self, node):
        self.gossip_protocol.leave(node)
        self._remove_node_from_shard_ring(node)

# Usage example:
store = ShardedKeyValueStore(10)
store.join_node(Node(3, "host3", 8083))
store.put("key1", "value1")
print(store.get("key1"))
store.leave_node(Node(3, "host3", 8083))
