def undo_redo():
    # Simple undo-redo function
    undo = []
    redo = []
    def undo_action(action):
        nonlocal undo
        undo.append(action)
        if undo:
            redo.clear()
    def redo_action():
        nonlocal redo
        redo.append(undo.pop())
    return undo_action, redo_action

