from abc import ABC, abstractmethod
from typing import Any

# Event bus
class EventBus:
    def __init__(self):
        self.events = []

    def post(self, event):
        self.events.append(event)

    def listen(self, callback):
        return lambda event: callback(event)

    def consume(self, event_type):
        return lambda event: event if event['type'] == event_type else None


# Abstract widget factory
class WidgetFactory(ABC):
    @abstractmethod
    def create_widget(self, widget_type: str) -> Any:
        pass


# Concrete widget factory for each platform
class QtWidgetFactory(WidgetFactory):
    def create_widget(self, widget_type: str) -> Any:
        if widget_type == 'button':
            return QPushButton('Button')
        elif widget_type == 'label':
            return QLabel('Label')
        else:
            raise ValueError(f'Unsupported widget type: {widget_type}')


class WxWidgetFactory(WidgetFactory):
    def create_widget(self, widget_type: str) -> Any:
        if widget_type == 'button':
            return wx.Button()
        elif widget_type == 'label':
            return wx.StaticText()
        else:
            raise ValueError(f'Unsupported widget type: {widget_type}')


class TextualWidgetFactory(WidgetFactory):
    def create_widget(self, widget_type: str) -> Any:
        if widget_type == 'button':
            return Button()
        elif widget_type == 'label':
            return Label()
        else:
            raise ValueError(f'Unsupported widget type: {widget_type}')


# Abstract widget
class Widget(ABC):
    def __init__(self, factory: WidgetFactory):
        self.factory = factory

    @abstractmethod
    def render(self):
        pass


# Concrete widget for each platform
class QPushButton(Widget):
    def __init__(self, text: str):
        super().__init__(QtWidgetFactory())
        self.text = text

    def render(self):
        print(f'Rendering Qt button with text: {self.text}')


class QLabel(Widget):
    def __init__(self, text: str):
        super().__init__(QtWidgetFactory())
        self.text = text

    def render(self):
        print(f'Rendering Qt label with text: {self.text}')


class wxButton(Widget):
    def __init__(self, text: str):
        super().__init__(WxWidgetFactory())
        self.text = text

    def render(self):
        print(f'Rendering wx button with text: {self.text}')


class wxStaticText(Widget):
    def __init__(self, text: str):
        super().__init__(WxWidgetFactory())
        self.text = text

    def render(self):
        print(f'Rendering wx static text with text: {self.text}')


class Button(Widget):
    def __init__(self, text: str):
        super().__init__(TextualWidgetFactory())
        self.text = text

    def render(self):
        print(f'Rendering textual button with text: {self.text}')


class Label(Widget):
    def __init__(self, text: str):
        super().__init__(TextualWidgetFactory())
        self.text = text

    def render(self):
        print(f'Rendering textual label with text: {self.text}')


# Event bus usage example
