from abc import ABC, abstractmethod
from typing import List, Dict, Any

# Define the base class for processing stages
class ProcessingStage(ABC):
    @abstractmethod
    def process(self, data: Any) -> Any:
        pass

# Define a concrete stage for data cleaning
class DataCleaner(ProcessingStage):
    def process(self, data: Any) -> Any:
        # Clean the data here
        return data

# Define a concrete stage for data transformation
class DataTransformer(ProcessingStage):
    def __init__(self, transformation_function):
        self.transformation_function = transformation_function

    def process(self, data: Any) -> Any:
        return self.transformation_function(data)

# Define a concrete stage for data filtering
class DataFilter(ProcessingStage):
    def __init__(self, filter_function):
        self.filter_function = filter_function

    def process(self, data: Any) -> Any:
        return self.filter_function(data)

# Define the pipeline class that uses the Chain of Responsibility pattern
class Pipeline:
    def __init__(self, stages: List[ProcessingStage]):
        self.stages = stages

    def process(self, data: Any) -> Any:
        for stage in self.stages:
            data = stage.process(data)
        return data

# Define a concrete pipeline with the data cleaning, transformation, and filtering stages
class DataPipeline(Pipeline):
    def __init__(self):
        self.stages = [
            DataCleaner(),
            DataTransformer(lambda x: x.upper()),
            DataFilter(lambda x: x.startswith("hello"))
        ]

# Define the main function to run the pipeline
def main():
    data = "hello world"
    pipeline = DataPipeline()
    result = pipeline.process(data)
    print(result)

# Run the main function
if __name__ == "__main__":
    main()
