from abc import ABC, abstractmethod
from typing import List

class Specification(ABC):
    @abstractmethod
    def is_satisfied(self, entity):
        pass

class FluentDSLSpecification(Specification):
    def __init__(self, rule):
        self.rule = rule
        self._and = None

    def and_(self, rule):
        self._and = FluentDSLSpecification(rule)
        return self

    def is_satisfied(self, entity):
        if self._and:
            return self._and.is_satisfied(entity) and self.rule.is_satisfied(entity)
        else:
            return self.rule.is_satisfied(entity)

class Rule:
    def is_satisfied(self, entity):
        raise NotImplementedError

class DiscountRule(Rule):
    def __init__(self, discount):
        self.discount = discount

    def is_satisfied(self, entity):
        return entity['price'] > self.discount

class ValidationRule(Rule):
    def __init__(self, min_value):
        self.min_value = min_value

    def is_satisfied(self, entity):
        return entity['value'] >= self.min_value

class RuleEngine:
    def __init__(self):
        self.rules = []

    def add_rule(self, rule):
        self.rules.append(rule)

    def evaluate(self, entity):
        specs = []
        for rule in self.rules:
            specs.append(FluentDSLSpecification(rule))
        for spec in specs:
            if not spec.is_satisfied(entity):
                return False
        return True

# Example usage
engine = RuleEngine()
engine.add_rule(DiscountRule(100))
engine.add_rule(ValidationRule(50))
entity = {'price': 150, 'value': 70}
print(engine.evaluate(entity))  # Output: True
