package main

import (
    "bufio"
    "bytes"
    "compress/gzip"
    "encoding/binary"
    "flag"
    "fmt"
    "io"
    "log"
    "math/rand"
    "os"
    "runtime"
    "sync"
    "time"
)

const (
    pageSize = 4096
)

type LogEntry struct {
    Time       string
    Method     string
    URL        string
    Status     int
    BytesSent  int
    Referrer  string
    UserAgent  string
}

func parseLogEntry(r io.Reader) (*LogEntry, error) {
    var entry LogEntry
    buf := make([]byte, pageSize)
    for {
        n, err := r.Read(buf)
        if err != nil {
            return &entry, err
        }
        if n == 0 {
            break
        }
        var header [16]byte
        if err := binary.Read(buf[:n], binary.LittleEndian, &header); err != nil {
            return &entry, err
        }
        entry.Time = header[0:4]
        entry.Method = header[4:8]
        entry.URL = header[8:24]
        entry.Status = header[24]
        entry.BytesSent = header[28]
        entry.Referrer = header[32:40]
        entry.UserAgent = header[40:64]
    }
    return &entry, nil
}

func compressLogEntries(entries []LogEntry) (io.Reader, error) {
    var buf bytes.Buffer
    writer := gzip.NewWriter(&buf)
    defer writer.Close()
    for _, entry := range entries {
        var header [16]byte
        binary.LittleEndian.PutUint64(&header[0:8], uint64(time.Now().UnixNano()))
        binary.LittleEndian.PutUint64(&header[8:16], uint64(entry.Status))
        if _, err := writer.Write(header); err != nil {
            return nil, err
        }
        if _, err := writer.Write([]byte(entry.Method)); err != nil {
            return nil, err
        }
        if _, err := writer.Write([]byte(entry.URL)); err != nil {
            return nil, err
        }
        if _, err := writer.Write([]byte(fmt.Sprintf("%d", entry.BytesSent))); err != nil {
            return nil, err
        }
        if _, err := writer.Write([]byte(entry.Referrer)); err != nil {
            return nil, err
        }
        if _, err := writer.Write([]byte(entry.UserAgent)); err != nil {
            return nil, err
        }
    }
    return &buf, nil
}

func main() {
    var (
        filename = flag.String("filename", "log.gz", "input file")
        cores    = flag.Int("cores", runtime.NumCPU(), "number of CPU cores")
    )
    flag.Parse()

    logEntries := make(chan LogEntry)
    go func() {
        f, err := os.Open(*filename)
        if err != nil {
            log.Fatal(err)
        }
        defer f.Close()
        r := bufio.NewReader(f)
        for {
            entry, err := parseLogEntry(r)
            if err != nil {
                log.Fatal(err)
            }
            logEntries <- *entry
        }
    }()
    close(logEntries)

    var wg sync.WaitGroup
    wg.Add(*cores)
    entries := make([]LogEntry, 0)
    for i := 0; i < *cores; i++ {
        go func() {
            defer wg.Done()
            for {
                entry := <-logEntries
                entries = append(entries, entry)
                if len(entries) >= 1000 {
                    compressLogEntries(entries)
                    entries = []LogEntry{}
                }
            }
        }()
    }
    go func() {
        wg.Wait()
        f, err := os.Create("output.log")
        if err != nil {
            log.Fatal(err)
        }
        defer f.Close()
        writer := bufio.NewWriter(f)
        for _, entry := range entries {
            _, err := writer.WriteString(fmt.Sprintf("%s %s %s %d %d %s %s\n", entry.Time, entry.Method, entry.URL, entry.Status, entry.BytesSent, entry.Referrer, entry.UserAgent))
            if err != nil {
                log.Fatal(err)
            }
        }
        writer.Flush()
    }()
    select {}
}

func benchmarkLogParser(b *testing.B) {
    rand.Seed(time.Now().UnixNano())
    var entries []LogEntry
    for i := 0; i < b.N; i++ {
        entries = append(entries, LogEntry{
            Time:       fmt.Sprintf("%d", rand.Intn(1000000000)),
            Method:     fmt.Sprintf("%c", rand.Intn(26)+97),
            URL:        fmt.Sprintf("%c", rand.Intn(26)+97) + "." + fmt.Sprintf("%c", rand.Intn(26)+97) + "." + fmt.Sprintf("%c", rand.Intn(26)+97) + "." + fmt.Sprintf("%c", rand.Intn(26)+97),
            Status:     rand.Intn(500),
            BytesSent:  rand.Intn(1024),
            Referrer:  fmt.Sprintf("%c", rand.Intn(26)+97) + "." + fmt.Sprintf("%c", rand.Intn(26)+97) + "." + fmt.Sprintf("%c", rand.Intn(26)+97) + "." + fmt.Sprintf("%c", rand.Intn(26)+97),
            UserAgent:  fmt.Sprintf("%c", rand.Intn(26)+97) + "." + fmt.Sprintf("%c", rand.Intn(26)+97) + "." + fmt.Sprintf("%c", rand.Intn(26)+97) + "." + fmt.Sprintf("%c", rand.Intn(26)+97),
        })
    }
    b.ResetTimer()
    logEntries := make(chan LogEntry)
    go func() {
        for _, entry := range entries {
            logEntries <- entry
        }
        close(logEntries)
    }()
    close(logEntries)
    var wg sync.WaitGroup
    wg.Add(10)
    entries := make([]LogEntry, 0)
    for i := 0; i < 10; i++ {
        go func() {
            defer wg.Done()
            for {
                entry := <-logEntries
                entries = append(entries, entry)
                if len(entries) >= 1000 {
                    compressLogEntries(entries)
                    entries = []LogEntry{}
                }
            }
        }()
    }
    go func() {
        wg.Wait()
    }()
    select {}
}
