// Import required modules
const express = require('express');
const jwt = require('jsonwebtoken');
const bcrypt = require('bcryptjs');
const helmet = require('helmet');
const cors = require('cors');
const { v4: uuidv4 } = require('uuid');

// Set up constants
const SECRET_KEY = process.env.SECRET_KEY || 'secret-key';
const ACCESS_TOKEN_EXPIRY = 3600; // 1 hour
const REFRESH_TOKEN_EXPIRY = 86400; // 1 day

// Set up JWT secret and keys
const jwtSecret = SECRET_KEY;

// Set up express app
const app = express();
app.use(helmet());
app.use(cors());

// Function to generate token
function generateToken(user) {
  const payload = {
    user: {
      id: user.id,
      username: user.username,
    },
  };
  const token = jwt.sign(payload, jwtSecret, { expiresIn: '1h' });
  return token;
}

// Function to verify token
function verifyToken(req, res, next) {
  const token = req.header('Authorization').replace('Bearer ', '');
  if (!token) return res.status(401).send({ error: 'Access denied. No token provided.' });
  try {
    const decoded = jwt.verify(token, jwtSecret);
    req.user = decoded.user;
    next();
  } catch (ex) {
    res.status(400).send({ error: 'Invalid token.' });
  }
}

// Function to create user
function createUser(req, res) {
  const { username, password } = req.body;
  const hashedPassword = bcrypt.hashSync(password, 10);
  const user = { id: uuidv4(), username, password: hashedPassword };
  const accessToken = generateToken(user);
  const refreshToken = generateToken(user);
  // Store refresh token in database
  // For simplicity, we will use a mock database
  const users = [{ id: user.id, username: user.username }];
  const userDoc = users[0];
  res.send({ accessToken, refreshToken, user: userDoc });
}

// Function to login
function login(req, res) {
  const { username, password } = req.body;
  const user = users.find((user) => user.username === username);
  if (!user) return res.status(404).send({ error: 'User not found.' });
  const isValidPassword = bcrypt.compareSync(password, user.password);
  if (!isValidPassword) return res.status(401).send({ error: 'Invalid password.' });
  const accessToken = generateToken(user);
  const refreshToken = generateToken(user);
  // Store refresh token in database
  // For simplicity, we will use a mock database
  const users = [{ id: user.id, username: user.username }];
  const userDoc = users[0];
  res.send({ accessToken, refreshToken, user: userDoc });
}

// Function to rotate secret key
function rotateSecretKey() {
  const newSecretKey = uuidv4();
  SECRET_KEY = newSecretKey;
  jwtSecret = newSecretKey;
}

// Refresh token endpoint
function refreshToken(req, res) {
  try {
    const refreshToken = req.header('Authorization').replace('Bearer ', '');
    const decoded = jwt.verify(refreshToken, jwtSecret);
    const user = decoded.user;
    const accessToken = generateToken(user);
    res.send({ accessToken });
  } catch (ex) {
    res.status(400).send({ error: 'Invalid token.' });
  }
}

// Endpoint to protect routes from CSRF
function protectRoutes(req, res, next) {
  if (req.method === 'GET' && req.headers['x-csrf-token']) {
    const csrfToken = req.headers['x-csrf-token'];
    if (csrfToken !== SECRET_KEY) {
      return res.status(403).send({ error: 'CSRF token mismatch.' });
    }
  }
  next();
}

// Endpoint to protect routes from replay attacks
function protectRoutesFromReplay(req, res, next) {
  if (req.method === 'GET' && req.headers['x-token-timestamp']) {
    const timestamp = req.headers['x-token-timestamp'];
    if (timestamp !== Date.now()) {
      return res.status(403).send({ error: 'Replay attack detected.' });
    }
  }
  next();
}

// Endpoint to protect routes from invalidated tokens
function protectRoutesFromInvalidatedTokens(req, res, next) {
  if (req.method === 'GET' && req.headers['x-token-issued-at']) {
    const issuedAt = req.headers['x-token-issued-at'];
    if (issuedAt < Date.now() - 1000 * 60 * 60) {
      return res.status(403).send({ error: 'Token has expired.' });
    }
  }
  next();
}

// Routes
app.post('/register', protectRoutesFromReplay, protectRoutesFromInvalidatedTokens, createUser);
app.post('/login', protectRoutesFromReplay, protectRoutesFromInvalidatedTokens, login);
app.get('/protected', verifyToken, protectRoutesFromReplay, protectRoutesFromInvalidatedTokens, protectRoutes, protectRoutesFromReplay, protectRoutesFromReplay, refreshToken);

// Rotate secret key after 1 hour
setInterval(rotateSecretKey, 3600000);

// Start server
const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});
