#include <algorithm>

// Function to merge two sorted files
void merge(const std::string& filename1, const std::string& filename2, const std::string& output_filename) {
    std::ifstream file1(filename1, std::ios::binary | std::ios::ate);
    std::ifstream file2(filename2, std::ios::binary | std::ios::ate);
    std::ofstream outputFile(output_filename, std::ios::binary);

    auto size1 = file1.tellg();
    auto size2 = file2.tellg();

    char* buffer1 = new char[size1];
    char* buffer2 = new char[size2];

    file1.seekg(0, std::ios::beg);
    file2.seekg(0, std::ios::beg);

    file1.read(buffer1, size1);
    file2.read(buffer2, size2);

    delete[] buffer1;
    delete[] buffer2;

    while (size1 > 0 && size2 > 0) {
        if (buffer1[0] <= buffer2[0]) {
            outputFile.write(buffer1, 1);
            size1 -= 1;
        } else {
            outputFile.write(buffer2, 1);
            size2 -= 1;
        }
    }

    while (size1 > 0) {
        outputFile.write(buffer1, size1);
        size1 = 0;
    }

    while (size2 > 0) {
        outputFile.write(buffer2, size2);
        size2 = 0;
    }

    outputFile.close();
}

// Function to sort a file using external merge sort
void externalMergeSort(const std::string& filename, const std::string& output_filename) {
    std::vector<std::string> chunks;

    // Split the file into chunks
    auto size = std::ifstream(filename, std::ios::binary | std::ios::ate).tellg();
    for (size_t i = 0; i < size; i += 1024 * 1024) { // 1MB chunks
        chunks.push_back(filename + "." + std::to_string(i / (1024 * 1024)) + ".tmp");
    }

    // Create a thread for each chunk
    std::vector<std::thread> threads;
    for (const auto& chunk : chunks) {
        threads.emplace_back(externalMergeSortHelper, chunk, output_filename, filename);
    }

    // Wait for all threads to finish
    for (auto& thread : threads) {
        thread.join();
    }

    // Remove temporary chunks
    for (const auto& chunk : chunks) {
        std::remove(chunk.c_str());
    }
}

// Helper function for external merge sort
void externalMergeSortHelper(const std::string& filename, const std::string& output_filename, const std::string& original_filename) {
    // Create a temporary file
    std::ofstream tempFile(filename, std::ios::binary);

    // Read from the original file and write to the temporary file
    std::ifstream file(original_filename, std::ios::binary | std::ios::ate);
    auto size = file.tellg();
    file.seekg(0, std::ios::beg);
    tempFile.write((char*)file.rdbuf(), size);

    tempFile.close();

    // Merge with other chunks
    merge(filename, original_filename + ".part", output_filename);
}

int main() {
    // Benchmarking
    const int chunkSize = 1024 * 1024; // 1MB chunks
    const int numChunks = 100; // 100 chunks

    auto start_time = std::chrono::high_resolution_clock::now();
    for (int i = 0; i < numChunks; i++) {
        std::string filename = "input_" + std::to_string(i) + ".bin";
        std::string output_filename = "output_" + std::to_string(i) + ".bin";
        externalMergeSort(filename, output_filename);
    }
    auto end_time = std::chrono::high_resolution_clock::now();
    auto duration = std::chrono::duration_cast<std::chrono::seconds>(end_time - start_time).count();

    std::cout << "Throughput: " << numChunks * chunkSize * 1024 / duration << " MB/s" << std::endl;

    start_time = std::chrono::high_resolution_clock::now();
    for (int i = 0; i < numChunks; i++) {
        std::string filename = "input_" + std::to_string(i) + ".bin";
        std::string output_filename = "output_" + std::to_string(i) + ".bin";
        externalMergeSort(filename, output_filename);
    }
    end_time = std::chrono::high_resolution_clock::now();
    duration = std::chrono::duration_cast<std::chrono::milliseconds>(end_time - start_time).count();

    std::cout << "I/O Wait Time: " << duration << " ms" << std::endl;

