# Define the plugin-based graph search framework
class GraphSearchFramework:
    def __init__(self):
        self.plugins = {}

    def add_plugin(self, plugin_name: str, plugin: Any):
        self.plugins[plugin_name] = plugin

    def remove_plugin(self, plugin_name: str):
        if plugin_name in self.plugins:
            del self.plugins[plugin_name]

    def get_plugin(self, plugin_name: str) -> Any:
        return self.plugins.get(plugin_name)

    def search(self, start: str, end: str) -> list:
        for plugin_name, plugin in self.plugins.items():
            if isinstance(plugin, Algorithm):
                try:
                    return plugin.find_path(start, end)
                except Exception as e:
                    logging.error(f"Error searching with {plugin_name}: {e}")
        return []

# Define the Dijkstra algorithm
class Dijkstra(Algorithm):
    def __init__(self, graph: Dict[str, Dict[str, int]]):
        super().__init__(graph)

    def find_path(self, start: str, end: str) -> list:
        distances = {node: float('infinity') for node in self.graph}
        distances[start] = 0
        previous_nodes = {node: None for node in self.graph}

        unvisited_nodes = list(self.graph.keys())
        while unvisited_nodes:
            current_node = min(unvisited_nodes, key=lambda node: distances[node])
            unvisited_nodes.remove(current_node)

            for neighbor, weight in self.graph[current_node].items():
                distance = distances[current_node] + weight
                if distance < distances[neighbor]:
                    distances[neighbor] = distance
                    previous_nodes[neighbor] = current_node

        path = []
        current_node = end
        while current_node:
            path.append(current_node)
            current_node = previous_nodes[current_node]
        path.reverse()

        return path

# Define the A* algorithm
class AStar(Algorithm):
    def __init__(self, graph: Dict[str, Dict[str, int]], heuristic: callable):
        super().__init__(graph)
        self.heuristic = heuristic

    def find_path(self, start: str, end: str) -> list:
        distances = {node: float('infinity') for node in self.graph}
        distances[start] = 0
        previous_nodes = {node: None for node in self.graph}

        unvisited_nodes = list(self.graph.keys())
        while unvisited_nodes:
            current_node = min(unvisited_nodes, key=lambda node: distances[node] + self.heuristic(node, end))
            unvisited_nodes.remove(current_node)

            for neighbor, weight in self.graph[current_node].items():
                distance = distances[current_node] + weight
                if distance < distances[neighbor]:
                    distances[neighbor] = distance
                    previous_nodes[neighbor] = current_node

        path = []
        current_node = end
        while current_node:
            path.append(current_node)
            current_node = previous_nodes[current_node]
        path.reverse()

        return path

# Define the Bellman-Ford algorithm
class BellmanFord(Algorithm):
    def __init__(self, graph: Dict[str, Dict[str, int]]):
        super().__init__(graph)

    def find_path(self, start: str, end: str) -> list:
        distances = {node: float('infinity') for node in self.graph}
        distances[start] = 0

        for _ in range(len(self.graph) - 1):
            for node in self.graph:
                for neighbor, weight in self.graph[node].items():
                    distance = distances[node] + weight
                    if distance < distances[neighbor]:
                        distances[neighbor] = distance

        path = []
        current_node = end
        while current_node:
            path.append(current_node)
            current_node = self.graph[current_node].get(current_node, None)
        path.reverse()

        return path

