    public static Set<String> detectPII(String text) {
        Set<String> pii = new HashSet<>();

        // Email pattern
        String emailPattern = "\\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\\.[A-Z|a-z]{2,}\\b";
        Pattern emailRegex = Pattern.compile(emailPattern, Pattern.CASE_INSENSITIVE);
        Matcher emailMatcher = emailRegex.matcher(text);
        while (emailMatcher.find()) {
            pii.add(emailMatcher.group());
        }

        // Phone number pattern
        String phoneNumberPattern = "\\b\\d{3}[-.]\\d{3}[-.]\\d{4}\\b";
        Pattern phoneNumberRegex = Pattern.compile(phoneNumberPattern, Pattern.CASE_INSENSITIVE);
        Matcher phoneNumberMatcher = phoneNumberRegex.matcher(text);
        while (phoneNumberMatcher.find()) {
            pii.add(phoneNumberMatcher.group());
        }

        // SSN pattern
        String ssnPattern = "\\b\\d{3}-\\d{2}-\\d{4}\\b";
        Pattern ssnRegex = Pattern.compile(ssnPattern, Pattern.CASE_INSENSITIVE);
        Matcher ssnMatcher = ssnRegex.matcher(text);
        while (ssnMatcher.find()) {
            pii.add(ssnMatcher.group());
        }

        // Credit card pattern
        String creditCardPattern = "\\b\\d{13,16}\\b";
        Pattern creditCardRegex = Pattern.compile(creditCardPattern, Pattern.CASE_INSENSITIVE);
        Matcher creditCardMatcher = creditCardRegex.matcher(text);
        while (creditCardMatcher.find()) {
            pii.add(creditCardMatcher.group());
        }

        return pii;
    }
