// knapsack.rs
pub trait KnapsackSolver {
    fn solve(&self, weights: Vec<i32>, values: Vec<i32>, capacity: i32) -> i32;
}

pub struct DynamicProgrammingSolver;
impl KnapsackSolver for DynamicProgrammingSolver {
    fn solve(&self, weights: Vec<i32>, values: Vec<i32>, capacity: i32) -> i32 {
        let n = weights.len();
        let mut dp = vec![vec![0; capacity + 1]; n + 1];

        for i in 1..=n {
            for j in 1..=capacity {
                if weights[i - 1] <= j {
                    dp[i][j] = std::cmp::max(dp[i - 1][j], dp[i - 1][j - weights[i - 1]] + values[i - 1]);
                } else {
                    dp[i][j] = dp[i - 1][j];
                }
            }
        }

        dp[n][capacity]
    }
}

pub struct BranchAndBoundSolver;
impl KnapsackSolver for BranchAndBoundSolver {
    fn solve(&self, weights: Vec<i32>, values: Vec<i32>, capacity: i32) -> i32 {
        fn is_feasible(weights: &Vec<i32>, values: &Vec<i32>, capacity: i32, current_weight: i32) -> bool {
            let mut current_value = 0;
            for (weight, value) in weights.iter().zip(values.iter()) {
                if *weight <= current_weight && *value > 0 {
                    current_value += *value;
                    current_weight -= *weight;
                }
            }
            current_value <= capacity
        }

        fn prune(weights: &Vec<i32>, values: &Vec<i32>, capacity: i32, current_weight: i32) -> bool {
            if is_feasible(weights, values, capacity, current_weight) {
                return true;
            }
            let mut best_value = 0;
            for (weight, value) in weights.iter().zip(values.iter()) {
                if *weight <= current_weight {
                    let value = value + prune(weights, values, capacity, current_weight - *weight);
                    if value > best_value {
                        best_value = value;
                    }
                }
            }
            best_value > 0
        }

        let n = weights.len();
        let mut best_value = 0;
        for i in 0..=n {
            if prune(weights, values, capacity, 0) {
                for j in 0..=n {
                    let mut current_value = 0;
                    for k in 0..=j {
                        if weights[k] <= capacity {
                            current_value = std::cmp::max(current_value, dp[k][capacity - weights[k]] + values[k]);
                        }
                    }
                    if current_value > best_value {
                        best_value = current_value;
                    }
                }
            }
        }
        best_value
    }
}

pub struct GreedySolver;
impl KnapsackSolver for GreedySolver {
    fn solve(&self, weights: Vec<i32>, values: Vec<i32>, capacity: i32) -> i32 {
        let mut greedy_values = vec![0; weights.len()];
        for i in 0..weights.len() {
            for j in i + 1..weights.len() {
                if values[j] > values[i] && weights[j] <= capacity - weights[i] {
                    greedy_values[i] = std::cmp::max(greedy_values[i], values[j]);
                }
            }
        }
        let mut current_weight = 0;
        let mut current_value = 0;
        for (weight, value) in weights.iter().zip(greedy_values.iter()) {
            if *weight <= capacity {
                current_weight += *weight;
                current_value += *value;
            }
        }
        current_value
    }
}

