package main

import (
    "bufio"
    "fmt"
    "log"
    "math/rand"
    "net"
    "sync"
    "time"
)

type Node struct {
    ID    int
    Peers []int
    State string
    Votes map[int]bool
    Log   []string
    Mu    sync.RWMutex
    Stop  chan bool
}

func NewNode(id int) *Node {
    return &Node{
        ID:    id,
        Peers: []int{1, 2, 3},
        State: "follower",
        Votes: make(map[int]bool),
        Log:   []string{},
        Stop:  make(chan bool),
    }
}

func (n *Node) Start() {
    n.Mu.Lock()
    n.State = "follower"
    n.Mu.Unlock()

    go n.run()
}

func (n *Node) JoinPeers(peers []int) {
    n.Mu.Lock()
    n.Peers = peers
    n.Mu.Unlock()
}

func (n *Node) AppendEntries(req int, term int, leader int, prevLogIndex int, entries []string) bool {
    n.Mu.Lock()
    n.Votes = make(map[int]bool)
    n.Log = append(n.Log, entries...)
    n.Mu.Unlock()

    if req == 1 && term > n.Term {
        n.Mu.Lock()
        n.State = "leader"
        n.Mu.Unlock()
        return true
    }

    return false
}

func (n *Node) RequestVotes(term int) bool {
    n.Mu.Lock()
    n.Votes = make(map[int]bool)
    n.Votes[n.ID] = true
    n.Mu.Unlock()

    if term > n.Term {
        n.Mu.Lock()
        n.State = "leader"
        n.Mu.Unlock()
        return true
    }

    return false
}

func (n *Node) getTerm() int {
    return n.Term
}

func (n *Node) getLog() []string {
    n.Mu.RLock()
    log := n.Log
    n.Mu.RUnlock()
    return log
}

func (n *Node) setState(state string) {
    n.Mu.Lock()
    n.State = state
    n.Mu.Unlock()
}

func (n *Node) logState() {
    n.Mu.Lock()
    log := n.Log
    n.Mu.Unlock()
    fmt.Println("Node", n.ID, "state:", n.State)
    fmt.Println("Log:", log)
}

func (n *Node) stop() {
    n.Stop <- true
}

func (n *Node) run() {
    for {
        select {
        case <-n.Stop:
            return
        case <-time.After(100 * time.Millisecond):
            n.logState()
            n.setState(fmt.Sprintf("state %d", rand.Intn(10)))
            n.logState()
        default:
        }
    }
}

type Network struct {
    Nodes map[int]*Node
    Stop  chan bool
}

func NewNetwork() *Network {
    return &Network{
        Nodes: make(map[int]*Node),
        Stop:  make(chan bool),
    }
}

func (n *Network) AddNode(node *Node) {
    n.Nodes[node.ID] = node
}

func (n *Network) Start() {
    for _, node := range n.Nodes {
        go node.Start()
    }
}

func (n *Network) SendRequest(nodeID int, term int, leader int, prevLogIndex int, entries []string) bool {
    node, ok := n.Nodes[nodeID]
    if !ok {
        return false
    }

    return node.AppendEntries(term, leader, prevLogIndex, entries)
}

func (n *Network) RequestVotes(nodeID int, term int) bool {
    node, ok := n.Nodes[nodeID]
    if !ok {
        return false
    }

    return node.RequestVotes(term)
}

func main() {
    network := NewNetwork()
    node1 := NewNode(1)
    node2 := NewNode(2)
    node3 := NewNode(3)

    network.AddNode(node1)
    network.AddNode(node2)
    network.AddNode(node3)

    network.Start()

    // Simulate network partitions
    network.SendRequest(1, 1, 1, 0, []string{"entry1", "entry2"})
    time.Sleep(200 * time.Millisecond)
    network.SendRequest(2, 2, 2, 0, []string{"entry3", "entry4"})

    // Simulate node failures
    close(network.Stop)
    time.Sleep(300 * time.Millisecond)
    network.SendRequest(1, 3, 3, 0, []string{"entry5", "entry6"})

    // Simulate network recoveries
    time.Sleep(400 * time.Millisecond)
    network.SendRequest(1, 4, 4, 0, []string{"entry7", "entry8"})
}
