// WordCount.scala

import scala.collection.mutable
import scala.concurrent.{Await, ExecutionContext, Future}
import scala.util.Random

import akka.actor.{ActorSystem, Props}
import akka.cluster.ClusterClient
import akka.cluster.ClusterClientSettings
import akka.cluster.ClusterSystem
import akka.cluster.node.ClusterNode
import akka.cluster.node.ClusterSystemSettings
import akka.cluster.system.ClusterSystemSettings
import akka.pattern.ask
import akka.stream.{Materializer, SourceQueueWithCompletion}
import akka.stream.stage.{Map, Split, Through}
import akka.stream.util.{BackpressureBehavior, FlowShape}

import akka.stream.scaladsl._
import akka.stream.scaladsl.DroppedMessages

import java.util.concurrent.atomic.AtomicInteger
import java.util.concurrent.atomic.AtomicLong

object WordCount {
  def main(args: Array[String]): Unit = {
    implicit val system: ActorSystem = ActorSystem("word-count")
    implicit val materializer: Materializer = Materializer(system)
    implicit val executionContext: ExecutionContext = system.dispatcher

    // Create a cluster client
    val clusterClient = ClusterClient(new ClusterClientSettings().withClusterName("word-count-cluster"))

    // Get the cluster node
    val clusterNode = clusterClient.cluster().join()

    // Create a queue for input
    val inputQueue = SourceQueueWithCompletion("input-queue", capacity = 100)

    // Create a queue for output
    val outputQueue = SourceQueueWithCompletion("output-queue", capacity = 100)

    // Create a word count function
    def wordCount(word: String): Future[Int] = {
      Future {
        val count = word.count(_ == 'a')
        count
      }
    }

    // Create a map stage to split words into words and counts
    val mapStage = Map("words" -> Split("words"))(
      wordCount _ andThen Through.put("count", _))
    val mapMaterializedValue = mapStage.materializedValue

    // Create a backpressure behavior
    val backpressureBehavior = BackpressureBehavior(maxBackpressureRequests = 100)

    // Create a stage with backpressure behavior
    val stage = mapStage.backpressure(backpressureBehavior)

    // Create a materialized value for the stage
    val materializedValue = stage.materializedValue

    // Define the worker actor
    case class WordCountWorker(inputQueue: SourceQueueWithCompletion[String], outputQueue: SourceQueueWithCompletion[Int])

    object WordCountWorker {
      def props(queue: SourceQueueWithCompletion[String]): Props = Props(new WordCountWorker(queue, outputQueue))
    }

    // Create a pool of worker actors
    val workers = (1 to 50).map(_ => system.actorOf(WordCountWorker.props(inputQueue), "worker-" + _.toString))

    // Start the workers
    workers.foreach(_.preStart())

    // Create a sink to print the output
    val sink = DroppedMessages(10).to(Sink.foreach(print))

    // Start the stage and sink
    materializedValue.runWith(sink)

    // Wait for all workers to stop
    workers.foreach(_.stop())
  }
}
