#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <immintrin.h>

// Define constants
#define N 1000000
#define M 2048
#define NUM_ITERATIONS 10

// Function to generate random data
float* generateRandomData(int size) {
    float* data = (float*)malloc(size * sizeof(float));
    for (int i = 0; i < size; i++) {
        data[i] = (float)rand() / RAND_MAX;
    }
    return data;
}

// Function to perform FFT
void fft(float* data, int n) {
    int i, j;
    float temp;

    for (i = 0; i < n; i++) {
        for (j = i + 1; j < n; j++) {
            if (data[j] < data[i]) {
                temp = data[i];
                data[i] = data[j];
                data[j] = temp;
            }
        }
    }

    for (i = 1; i < n; i *= 2) {
        int block = i * 2;

        for (j = 0; j < n; j += block) {
            for (int k = 0; k < block / 2; k++) {
                float w = (float)cos(2 * M_PI * (j / (double)block + 1.0 / (double)n));
                temp = data[j + k] - data[j + k + i] * w;
                data[j + k] = data[j + k + i] + temp;
                data[j + k + i] = data[j + k] - temp;
            }
        }
    }
}

// Function to perform inverse FFT
void ifft(float* data, int n) {
    int i, j;
    float temp;

    for (i = 0; i < n; i++) {
        for (j = i + 1; j < n; j++) {
            if (data[j] < data[i]) {
                temp = data[i];
                data[i] = data[j];
                data[j] = temp;
            }
        }
    }

    for (i = 1; i < n; i *= 2) {
        int block = i * 2;

        for (j = 0; j < n; j += block) {
            for (int k = 0; k < block / 2; k++) {
                float w = (float)cos(2 * M_PI * (j / (double)block + 1.0 / (double)n));
                temp = data[j + k] + data[j + k + i] * w;
                data[j + k] = (data[j + k] + temp) / 2;
                data[j + k + i] = (data[j + k + i] - temp) / 2;
            }
        }
    }
}

int main() {
    // Initialize random number generator
    srand(time(NULL));

    // Allocate memory for data
    float* data = generateRandomData(N);

    // Measure CPU cycle counts
    double start, end;
    start = clock();
    fft(data, N);
    end = clock();
    printf("Time taken for FFT: %f ms\n", (end - start) / 1000.0);

    // Measure CPU cycle counts for FFTW
    start = clock();
    fftw_complex* fftwData = fftw_malloc(sizeof(fftw_complex) * N);
    for (int i = 0; i < N; i++) {
        fftwData[i].re = (float)rand() / RAND_MAX;
        fftwData[i].im = (float)rand() / RAND_MAX;
    }
    fftw_plan plan = fftw_plan_dft_1d(N, fftwData, fftwData, FFTW_FORWARD, FFTW_ESTIMATE);
    fftw_execute(plan);
    fftw_destroy_plan(plan);
    end = clock();
    printf("Time taken for FFTW: %f ms\n", (end - start) / 1000.0);

    // Free memory
    fftw_free(fftwData);
    free(data);

    return 0;
}
