import hashlib
import hmac
import logging
import time
import numpy as np
from scipy import spatial
from collections import defaultdict
from functools import lru_cache
from flask import Flask, request, jsonify

app = Flask(__name__)

# LSH parameters
num_hash_functions = 10
num_points = 1000
num_dimensions = 10
hashing_function = lambda x: hashlib.sha256(x.encode()).digest()

# Constant-time hashing
def constant_time_hash(x):
    return hmac.new(b'secret_key', x.encode(), hashlib.sha256).hexdigest()

# Validate inputs
def validate_input(point):
    if not isinstance(point, list) or len(point) != num_dimensions:
        return False
    for x in point:
        if not isinstance(x, (int, float)):
            return False
    return True

# Locality-sensitive hashing
class LSH:
    def __init__(self, num_hash_functions, num_points, num_dimensions, hashing_function):
        self.num_hash_functions = num_hash_functions
        self.num_points = num_points
        self.num_dimensions = num_dimensions
        self.hashing_function = hashing_function
        self.index_table = defaultdict(list)

    def _hash(self, point):
        hashes = []
        for _ in range(self.num_hash_functions):
            hashes.append(constant_time_hash(str(point)))
        return hashes

    def add_point(self, point):
        if not validate_input(point):
            return
        hashes = self._hash(point)
        for i, hash in enumerate(hashes):
            self.index_table[hash].append(i)

    def query(self, query_point):
        if not validate_input(query_point):
            return
        hashes = self._hash(query_point)
        distances = []
        for hash in hashes:
            for i in self.index_table[hash]:
                distance = spatial.distance.euclidean(query_point, self.points[i])
                distances.append((distance, i))
        distances.sort(key=lambda x: x[0])
        return [x[1] for x in distances]

# Rate limiting
class RateLimiter:
    def __init__(self, max_requests):
        self.max_requests = max_requests
        self.requests = 0
        self.last_reset = time.time()

    def allow(self, point):
        if self.requests >= self.max_requests:
            return False
        self.requests += 1
        if time.time() - self.last_reset > 60:  # reset every minute
            self.requests = 0
            self.last_reset = time.time()
        return True

# Service
class NearestNeighborService:
    def __init__(self):
        self.lsh = LSH(num_hash_functions, num_points, num_dimensions, hashing_function)
        self.rate_limiter = RateLimiter(max_requests=10)

    def add_point(self, point):
        if not self.rate_limiter.allow(point):
            return
        self.lsh.add_point(point)

    def query(self, query_point):
        if not self.rate_limiter.allow(query_point):
            return
        return self.lsh.query(query_point)

# API
service = NearestNeighborService()

@app.route('/add_point', methods=['POST'])
def add_point():
    point = request.json['point']
    service.add_point(point)
    return jsonify({'message': 'Point added successfully'})

@app.route('/query', methods=['POST'])
def query():
    query_point = request.json['query_point']
    return jsonify({'points': service.query(query_point)})

if __name__ == '__main__':
    app.run(debug=True)
