#include <atomic>
#include <condition_variable>
#include <vector>
#include <chrono>
#include <random>

// Define a struct to hold the order data
struct Order {
    std::string type;
    double price;
    double quantity;
};

// Define a lock-free queue to hold the orders
class LockFreeQueue {
private:
    struct Node {
        Order order;
        Node* next;
    };

    std::atomic<Node*> head_;
    std::atomic<Node*> tail_;
    std::mutex mtx_;

public:
    LockFreeQueue() : head_(nullptr), tail_(nullptr) {}

    // Enqueue an order
    void enqueue(const Order& order) {
        Node* newNode = new Node{order, nullptr};
        while (true) {
            Node* prevTail = tail_.exchange(nullptr);
            Node* next = prevTail ? prevTail->next : nullptr;
            if (next) {
                Node* nextNext = next->next;
                next->next = newNode;
                newNode->next = nextNext;
                break;
            }
            std::lock_guard<std::mutex> lock(mtx_);
            if (prevTail) {
                prevTail->next = newNode;
            } else {
                head_ = newNode;
            }
        }
    }

    // Dequeue an order
    bool dequeue(Order& order) {
        while (true) {
            Node* head = head_.load();
            if (head) {
                Order* orderPtr = &head->order;
                Node* next = head->next;
                if (next) {
                    orderPtr->price = next->order.price;
                    orderPtr->quantity = next->order.quantity;
                    head->next = next->next;
                    head = next;
                } else {
                    delete head;
                    head_ = nullptr;
                    return true;
                }
            } else {
                std::unique_lock<std::mutex> lock(mtx_);
                while (head_.load() == nullptr) {
                    lock.wait(lock);
                }
                head = head_.load();
                if (!head) {
                    lock.unlock();
                    return false;
                }
            }
            order = *orderPtr;
            lock.unlock();
            return true;
        }
    }
};

// Define a CPU affinity function
void cpu_affinity(int cpu) {
    std::thread::id currentCpuId = std::this_thread::get_id();
    if (currentCpuId != std::thread::id(cpu)) {
        std::thread::set_affinity(currentCpuId, std::thread::affinity_mask(cpu));
    }
}

// Define a benchmark function
void benchmark(const std::string& name, LockFreeQueue& queue) {
    std::random_device rd;
    std::mt19937 gen(rd());
    std::uniform_real_distribution<double> dis(0.0, 1.0);
    std::uniform_int_distribution<int> idDis(0, 100);

    auto placeOrder = [&]() {
        std::string type = "buy" + std::to_string(idDis(gen));
        double price = dis(gen);
        double quantity = dis(gen);
        queue.enqueue(Order{type, price, quantity});
    };

    auto checkMatch = [&]() {
        Order order;
        if (queue.dequeue(order)) {
            std::cout << name << ": matched order - type: " << order.type << ", price: " << order.price << ", quantity: " << order.quantity << std::endl;
        } else {
            std::cout << name << ": no match" << std::endl;
        }
    };

    std::vector<std::thread> threads;
    for (int i = 0; i < 100; ++i) {
        threads.emplace_back([&]() {
            cpu_affinity(i % 4);  // Try each of the 4 CPU cores
            for (int j = 0; j < 10000; ++j) {
                placeOrder();
            }
        });
    }

    for (int i = 0; i < 1000; ++i) {
        for (auto& thread : threads) {
            thread.join();
        }
        for (int j = 0; j < 10000; ++j) {
            checkMatch();
        }
    }
}

int main() {
    LockFreeQueue queue;

    // Benchmark
    benchmark("High-frequency trading", queue);

    return 0;
}
