use tokio;
use tokio::sync::{RwLock, RwLockReadGuard};
use tokio::time::{interval, Instant};
use tokio_tungstenite::connect_async;
use tokio_tungstenite::tungstenite::Message;
use serde_json;

struct TelemetryService {
    clients: RwLock<Vec<(String, String)>>,
    log: RwLock<Vec<Instant>>,
    health_check_interval: tokio::time::Interval,
}

impl TelemetryService {
    async fn new() -> Self {
        let clients = RwLock::new(Vec::new());
        let log = RwLock::new(Vec::new());
        let health_check_interval = interval(1, tokio::time::Duration::from_secs(1));

        Self {
            clients,
            log,
            health_check_interval,
        }
    }

    async fn connect(&self, client_id: String, endpoint: String) {
        let mut clients = self.clients.write().await;
        clients.push((client_id.clone(), endpoint));
    }

    async fn send(&self, client_id: String, message: String) {
        let mut clients = self.clients.read().await;
        for (id, endpoint) in clients.iter() {
            if id == client_id {
                // Implement your message sending logic here
                println!("Sending message to {}: {}", id, endpoint);
                break;
            }
        }
    }

    async fn health_check(&self) -> String {
        let mut log = self.log.write().await;
        let now = Instant::now();
        log.push(now);

        "Service is up".to_string()
    }

    async fn run(&self) {
        loop {
            self.health_check_interval.tick().await;
            let now = Instant::now();
            let mut log = self.log.write().await;
            if log.len() > 10 {
                log.truncate(10);
            }

            let mut clients = self.clients.read().await;
            for (id, endpoint) in clients.iter() {
                if endpoint.is_empty() {
                    clients.remove(id);
                }
            }
        }
    }
}

