  host: 'localhost',
  port: 6379
});

// Sticky session balancing
const stickySession = require('sticky-session')({
  cookieName: 'sticky-session',
  cookieOptions: {
    httpOnly: true,
    maxAge: 60 * 60 * 1000 // 1 hour
  }
});

// Load testing
const loadTesting = (numConnections) => {
  return new Promise((resolve, reject) => {
    const connections = [];
    for (let i = 0; i < numConnections; i++) {
      const socket = io.connect('http://localhost:3000');
      connections.push(socket);
    }
    const interval = setInterval(() => {
      connections.forEach((connection) => {
        connection.emit('message', `User ${i} connected`);
        connection.emit('message', `User ${i} sent a message`);
      });
    }, 1000);
    setTimeout(() => {
      connections.forEach((connection) => {
        connection.close();
      });
      clearInterval(interval);
      resolve();
    }, numConnections * 1000);
  });
};

// Auto-scale across hundreds of instances
const cluster = require('cluster');
if (cluster.isMaster) {
  const numInstances = 100;
  for (let i = 0; i < numInstances; i++) {
    if (i === 0) {
      // Master instance
      app.listen(3000, () => {
        console.log('Master instance listening on port 3000');
      });
    } else {
      // Worker instance
      const worker = cluster.fork();
      worker.on('exit', () => {
        console.log(`Worker instance ${i} exited`);
      });
    }
  }
  loadTesting(100000).then(() => {
    console.log('Linear user scaling up to 100k concurrent connections');
  }).catch((error) => {
    console.error('Error during load testing:', error);
  });
} else {
  // Worker instance
  stickySession(req, res, () => {
    io.emit('message', `User ${process.pid} connected`);
    io.emit('message', `User ${process.pid} sent a message`);
  });
}
