package main

import (
    "fmt"
    "log"
    "runtime"
    "sync"

    "github.com/go-ffmpeg/ffmpeg"
    "github.com/gorilla/websocket"
    "github.com/segmentio/ffmpeg-golang"

    "github.com/evccnet/workerpool"
)

const (
    // Video codec settings
    codec  = "libx264"
    profile = "main"
    level  = "5"

    // Video resolution
    width  = 1280
    height = 720

    // Bitrate
    bitrate = 500000

    // Worker pool settings
    numWorkers = 4
)

func main() {
    // Check if GPU is available
    if runtime.GOROOT() != "/usr" && runtime.GOROOT() != "/usr/local" {
        log.Fatal("No GPU available")
    }

    // Create a new ffmpeg instance
    cmd := ffmpeg.NewCmd()
    cmd.SetCpuUsage(true)
    cmd.SetGPU(true)
    cmd.SetGPUWorkload(ffmpeg.GPUWorkloadVideoEncoding)

    // Start ffmpeg
    cmd.Start()

    // Create a new WebSocket server
    server, err := websocket.Server(&websocket.ServerConfig{
        ReadBufferSize:  1024,
        WriteBufferSize: 1024,
    })
    if err != nil {
        log.Fatal(err)
    }

    // Start the server
    if err := server.Serve(":8080"); err != nil {
        log.Fatal(err)
    }

    // Create a new worker pool
    pool, err := workerpool.NewPool(numWorkers)
    if err != nil {
        log.Fatal(err)
    }

    // Handle WebSocket connections
    for {
        conn, _, err := server.NextReader()
        if err != nil {
            log.Println(err)
            continue
        }
        go handleConnection(conn, pool)
    }
}

func handleConnection(conn *websocket.Conn, pool *workerpool.Pool) {
    // Read video data from the client
    var videoData []byte
    for {
        var err error
        videoData, err = conn.ReadMessage()
        if err != nil {
            break
        }
    }

    // Encode the video data
    cmd := ffmpeg.NewCmd()
    cmd.SetInput(videoData)
    cmd.SetOutput(videoData)
    cmd.SetCodec(codec)
    cmd.SetProfile(profile)
    cmd.SetLevel(level)
    cmd.SetBitrate(bitrate)
    cmd.SetWidth(width)
    cmd.SetHeight(height)

    // Use a worker to encode the video
    go func() {
        if err := cmd.Run(); err != nil {
            log.Println(err)
        }
    }()

    // Send the encoded video data back to the client
    var encodedVideoData []byte
    if err := cmd.GetOutput(&encodedVideoData); err != nil {
        log.Println(err)
    }
    conn.WriteMessage(websocket.TextMessage, encodedVideoData)
}

func getWorkerPool() *workerpool.Pool {
    return workerpool.NewPool(numWorkers)
}
