// angular-vue-migration.js
const fs = require('fs');
const path = require('path');

// Migrate AngularJS v1.x components to Vue.js 3 components
function migrateComponents() {
  const angularComponentsDir = './angular-components';
  const vueComponentsDir = './vue-components';

  fs.mkdirSync(vueComponentsDir);

  fs.readdirSync(angularComponentsDir).forEach((file) => {
    const filePath = path.join(angularComponentsDir, file);
    const fileContent = fs.readFileSync(filePath, 'utf8');
    const newContent = fileContent.replace(/angularJS/g, 'vue');
    fs.writeFileSync(path.join(vueComponentsDir, file), newContent);
  });
}

// Extract shared services into TypeScript modules
function extractServices() {
  const sharedServicesDir = './shared-services';
  const tsModulesDir = './ts-modules';

  fs.mkdirSync(tsModulesDir);

  fs.readdirSync(sharedServicesDir).forEach((file) => {
    const filePath = path.join(sharedServicesDir, file);
    const fileContent = fs.readFileSync(filePath, 'utf8');
    const newContent = fileContent.replace(/typescript/g, 'ts');
    const newFile = file.replace('.js', '.ts');
    fs.writeFileSync(path.join(tsModulesDir, newFile), newContent);
  });
}

// Setup Storybook
function setupStorybook() {
  const storybookDir = './storybook';

  if (!fs.existsSync(storybookDir)) {
    fs.mkdirSync(storybookDir);
  }

  const packageJson = require('./package.json');
  packageJson.devDependencies.storybook = '^5.5.10';
  fs.writeFileSync('./package.json', JSON.stringify(packageJson, null, 2));
}

// Setup ESLint
function setupESLint() {
  const eslintDir = './.eslintconfig';

  if (!fs.existsSync(eslintDir)) {
    fs.writeFileSync(eslintDir, 'root: true\n');
  }
}

// Setup Prettier
function setupPrettier() {
  const prettierDir = './.prettierrc';

  if (!fs.existsSync(prettierDir)) {
    fs.writeFileSync(prettierDir, '{ "printWidth": 120, "tabWidth": 2, "useTabs": false, "semi": true, "singleQuote": true, "trailingComma": "all", "bracketSpacing": true, "jsxBracketSameLine": true, "tabLength": 2 }');
  }
}

// Run migration
migrateComponents();
extractServices();
setupStorybook();
setupESLint();
setupPrettier();
